#include <bits/stdc++.h>
using namespace std;
int k,p[6];
long long dp[31][31][31][31][31];
int main(){
	while(1){
		scanf("%d",&k);
		if(k==0)
			break;
		for(int i=1;i<=k;i++)
			scanf("%d",&p[i]);
		for(int i=k+1;i<6;i++)
			p[i]=0;
		for(int a=0;a<=p[1];a++)
			for(int b=0;b<=min(a,p[2]);b++)
				for(int c=0;c<=min(b,p[3]);c++)
					for(int d=0;d<=min(c,p[4]);d++)
						for(int e=0;e<=min(d,p[5]);e++){
							if(!a)
								dp[a][b][c][d][e]=1;
							else if(!b)
								dp[a][b][c][d][e]=dp[a-1][b][c][d][e];
							else if(!c)
								dp[a][b][c][d][e]=dp[a-1][b][c][d][e]+dp[a][b-1][c][d][e];
							else if(!d)
								dp[a][b][c][d][e]=dp[a-1][b][c][d][e]+dp[a][b-1][c][d][e]+dp[a][b][c-1][d][e];
							else if(!e)
								dp[a][b][c][d][e]=dp[a-1][b][c][d][e]+dp[a][b-1][c][d][e]+dp[a][b][c-1][d][e]+dp[a][b][c][d-1][e];
							else
								dp[a][b][c][d][e]=dp[a-1][b][c][d][e]+dp[a][b-1][c][d][e]+dp[a][b][c-1][d][e]+dp[a][b][c][d-1][e]+dp[a][b][c][d][e-1];
						}
		printf("%lld\n",dp[p[1]][p[2]][p[3]][p[4]][p[5]]);
	}
	return 0;
